qry:select.qry:xquery:
				for $r in SQL('
SELECT
{%?(#SOURCE:@c_distribucion='CC')  {% DisCC.cc as c, ORG08_CS_COSTO.d_centro_costo as d, %} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC') {% ORG09_GR_CCOSTO.c_grupo_ccosto as c, ORG09_GR_CCOSTO.d_grupo_ccosto as d, %} {% %} %}
sum(round(P20.n_valor*DisCC.por,2)) AS value, l29.c_operacion
FROM 
LIQ19_LIQUIDACION as l19,
LIQ19_EJECUCIONES as e19,
LIQ99_LIQUIDACION as l99,
LIQ99_RECIBOS as R99,
LIQ20_TOT_LIQ_PER as l20,
LIQ20_CONC_LIQ_PER as P20,
LIQ14_CONCEPTOS as l14,
LIQ96_CONCEPTOS as L96,
LIQ97_PERSONAL_EMP as l97,
LIQ29_CUENTAS_TC as l29,
(select              
P.oi_per_emp_ddo, 
iifisnull(D.c_centro_costo, P.c_centro_costo_ult) as cc, 
iifisnull(D.n_p_distrib, 1) as por
from 
liq97_personal_emp as P, 
liq97_distrib_cos as D
join
P.oi_per_emp_ddo left outer D.oi_per_emp_ddo
) as DisCC
{%?(#SOURCE:@c_distribucion='CC' or #SOURCE:@ccosto!='' or #SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG08_CS_COSTO%} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG09_GR_CCOSTO%} {% %} %}
{%?(#SOURCE:@convenios!='') {%, ORG18_CONVENIOS %} {% %} %}

JOIN
l19.oi_liquidacion INNER e19.oi_liquidacion,
e19.oi_liquidacion_ddo INNER l99.oi_liquidacion_ddo,
l99.oi_liquidacion_ddo INNER R99.oi_liquidacion_ddo,
R99.oi_tot_liq_per INNER l20.oi_tot_liq_per,
l20.oi_tot_liq_per INNER P20.oi_tot_liq_per,
P20.oi_concepto_ddo INNER L96.oi_concepto_ddo,
L96.c_concepto INNER l14.c_concepto,
l20.oi_per_emp_ddo INNER l97.oi_per_emp_ddo,
DisCC.oi_per_emp_ddo INNER l97.oi_per_emp_ddo,
l29.oi_tipo_concepto INNER l14.oi_tipo_concepto
{%?(#SOURCE:@c_distribucion='CC' or #SOURCE:@ccosto!='' or #SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, DisCC.cc INNER ORG08_CS_COSTO.c_centro_costo%} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG08_CS_COSTO.oi_grupo_ccosto INNER ORG09_GR_CCOSTO.oi_grupo_ccosto %} {% %} %}
{%?(#SOURCE:@convenios!='') {%, l97.c_convenio INNER ORG18_CONVENIOS.c_convenio %} {% %} %}

WHERE
  l29.oi_cuenta_contable = {#SOURCE:@oi_cuenta_contable} 
AND l19.oi_empresa = {#PARAMIN:@oi_empresa} 
AND l19.e_periodo = {#PARAMIN:@e_periodo}
AND l99.c_estado = \'F\'
AND P20.n_valor != 0
{%? (#PARAMIN:@oi_liqs!=''){% AND l19.oi_liquidacion in ({%= #PARAMIN:@oi_liqs %}) %} {% %} %}
{%? (#SOURCE:@gccosto!=''){% AND ORG09_GR_CCOSTO.oi_grupo_ccosto {%?(#SOURCE:@l_excluir_gccos='1') {% not in %} {% in %} %} ({%=#SOURCE:@gccosto%}) %} {% %} %}
{%? (#SOURCE:@ccosto!='')	{% AND ORG08_CS_COSTO.oi_centro_costo {%?(#SOURCE:@l_excluir_ccos='1') {% not in %} {% in %} %} ({%=#SOURCE:@ccosto%}) %} {% %} %}
{%? (#SOURCE:@convenios!='') {% AND ORG18_CONVENIOS.oi_convenio {%?(#SOURCE:@l_excluir_convenio='1') {% not in %} {% in %} %} ({%=#SOURCE:@convenios%}) %} {% %} %}

GROUP BY l29.c_operacion
{%?(#SOURCE:@c_distribucion='CC')  {% ,DisCC.cc, ORG08_CS_COSTO.d_centro_costo %} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC')  {% ,ORG09_GR_CCOSTO.c_grupo_ccosto, ORG09_GR_CCOSTO.d_grupo_ccosto %} {% %} %}
')/ROWS/ROW
{%?(#SOURCE:@c_distribucion!='') {% , $s in $CUENTA/ROW
join $r/@c inner $s/@c %} {% %} %}

				for $r in SQL('
SELECT
{%?(#SOURCE:@c_distribucion='CC')  {% DisCC.cc as c, ORG08_CS_COSTO.d_centro_costo as d, %} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC') {% ORG09_GR_CCOSTO.c_grupo_ccosto as c, ORG09_GR_CCOSTO.d_grupo_ccosto as d, %} {% %} %}
sum(round(P20.n_valor*DisCC.por,2)) AS value, l29.c_operacion
FROM 
LIQ19_LIQUIDACION as l19,
LIQ19_EJECUCIONES as e19,
LIQ99_LIQUIDACION as l99,
LIQ99_RECIBOS as R99,
LIQ20_TOT_LIQ_PER as l20,
LIQ20_CONC_LIQ_PER as P20,
LIQ14_CONCEPTOS as l14,
LIQ96_CONCEPTOS as L96,
LIQ97_PERSONAL_EMP as l97,
LIQ29_CUENTAS_CPT as l29,
(select              
P.oi_per_emp_ddo, 
iifisnull(D.c_centro_costo, P.c_centro_costo_ult) as cc, 
iifisnull(D.n_p_distrib, 1) as por
from 
liq97_personal_emp as P, 
liq97_distrib_cos as D
join
P.oi_per_emp_ddo left outer D.oi_per_emp_ddo
) as DisCC
{%?(#SOURCE:@c_distribucion='CC' or #SOURCE:@ccosto!='' or #SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG08_CS_COSTO%} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG09_GR_CCOSTO%} {% %} %}
{%?(#SOURCE:@convenios!='') {%, ORG18_CONVENIOS %} {% %} %}

JOIN
l19.oi_liquidacion INNER e19.oi_liquidacion,
e19.oi_liquidacion_ddo INNER l99.oi_liquidacion_ddo,
l99.oi_liquidacion_ddo INNER R99.oi_liquidacion_ddo,
R99.oi_tot_liq_per INNER l20.oi_tot_liq_per,
l20.oi_tot_liq_per INNER P20.oi_tot_liq_per,
P20.oi_concepto_ddo INNER L96.oi_concepto_ddo,
L96.c_concepto INNER l14.c_concepto,
l20.oi_per_emp_ddo INNER l97.oi_per_emp_ddo,
DisCC.oi_per_emp_ddo INNER l97.oi_per_emp_ddo,
l29.oi_concepto INNER l14.oi_concepto
{%?(#SOURCE:@c_distribucion='CC' or #SOURCE:@ccosto!='' or #SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, DisCC.cc INNER ORG08_CS_COSTO.c_centro_costo%} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC' or #SOURCE:@gccosto!='') {%, ORG08_CS_COSTO.oi_grupo_ccosto INNER ORG09_GR_CCOSTO.oi_grupo_ccosto %} {% %} %}
{%?(#SOURCE:@convenios!='') {%, l97.c_convenio INNER ORG18_CONVENIOS.c_convenio %} {% %} %}

WHERE
l29.oi_cuenta_contable = {#SOURCE:@oi_cuenta_contable} 
AND l19.oi_empresa = {#PARAMIN:@oi_empresa} 
AND l19.e_periodo = {#PARAMIN:@e_periodo}
AND l99.c_estado = \'F\'
AND P20.n_valor != 0
{%? (#PARAMIN:@oi_liqs!=''){% AND l19.oi_liquidacion in ({%= #PARAMIN:@oi_liqs %}) %} {% %} %}
{%? (#SOURCE:@gccosto!=''){% AND ORG09_GR_CCOSTO.oi_grupo_ccosto {%?(#SOURCE:@l_excluir_gccos='1') {% not in %} {% in %} %} ({%=#SOURCE:@gccosto%}) %} {% %} %}
{%? (#SOURCE:@ccosto!='')	{% AND ORG08_CS_COSTO.oi_centro_costo {%?(#SOURCE:@l_excluir_ccos='1') {% not in %} {% in %} %} ({%=#SOURCE:@ccosto%}) %} {% %} %}
{%? (#SOURCE:@convenios!='') {% AND ORG18_CONVENIOS.oi_convenio {%?(#SOURCE:@l_excluir_convenio='1') {% not in %} {% in %} %} ({%=#SOURCE:@convenios%}) %} {% %} %}

GROUP BY l29.c_operacion
{%?(#SOURCE:@c_distribucion='CC')  {% ,DisCC.cc, ORG08_CS_COSTO.d_centro_costo %} {% %} %}
{%?(#SOURCE:@c_distribucion='GCC')  {% ,ORG09_GR_CCOSTO.c_grupo_ccosto, ORG09_GR_CCOSTO.d_grupo_ccosto %} {% %} %}
')/ROWS/ROW
{%?(#SOURCE:@c_distribucion!='') {% , $s in $CUENTA/ROW
join $r/@c inner $s/@c %} {% %} %}
